arguments.new_str:
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Fixed: CacheService was singleton consuming scoped IUserService.
// .NET 9 enables ValidateScopes/ValidateOnBuild in Development, which
// would throw at startup. Use IServiceScopeFactory to resolve correctly.
builder.Services.AddSingleton<ICacheService>(sp =>
{
    using var scope = sp.CreateScope();
    return new CacheService(scope.ServiceProvider.GetRequiredService<IUserService>());
});
builder.Services.AddHttpClient("api")
    // Fixed: ConfigureHttpMessageHandlerBuilder is obsolete.
    // Fixed: Default primary handler is now SocketsHttpHandler in .NET 9,
    //        so casting to HttpClientHandler would throw InvalidCastException.
    .UseSocketsHttpHandler((handler, _) =>
    {
        handler.UseCookies = false;
    })
    // Fixed: .NET 9 redacts all HTTP header values in Trace logs by default.
    // Opt in to logging the headers you need for debugging.
    .RedactLoggedHeaders(h => h.StartsWith("Auth", StringComparison.OrdinalIgnoreCase));
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // Fixed: .NET 9.0.6+ ignores X-Forwarded-* from unknown proxies.
    // Configure your actual proxy address here.
    options.KnownProxies.Add(System.Net.IPAddress.Loopback);
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

